### 3. **Protocol Buffers (Proto) 파일**

```
/tmp/claude-eval-embed-20260226-135237/tag/protobuf/src/main/proto/chat/
├── chat_service.proto         (chat 서비스 gRPC 정의)
└── chat_message.proto         (chat 관련 메시지 정의)
```

**주요 Proto 정의 (예상):**

- **chat_service.proto**
  ```protobuf
  syntax = "proto3";
  package chat;

  option java_multiple_files = true;
  option java_package = "com.maum.backend.protobuf.chat";

  service ChatService {
    rpc CreateChatRoom(CreateChatRoomRequest) returns (CreateChatRoomResponse);
    rpc GetChatRoom(GetChatRoomRequest) returns (GetChatRoomResponse);
    rpc ListChatRooms(ListChatRoomsRequest) returns (ListChatRoomsResponse);
    rpc SendMessage(SendMessageRequest) returns (SendMessageResponse);
    rpc ListMessages(ListMessagesRequest) returns (ListMessagesResponse);
    rpc MarkAsRead(MarkAsReadRequest) returns (MarkAsReadResponse);
  }

  message CreateChatRoomRequest {
    string user_id = 1;
    string other_user_id = 2;
  }

  message CreateChatRoomResponse {
    ChatRoom chat_room = 1;
  }

  message GetChatRoomRequest {
    string room_id = 1;
  }

  message GetChatRoomResponse {
    ChatRoom chat_room = 1;
  }

  message ListChatRoomsRequest {
    string user_id = 1;
    int32 limit = 2;
    int32 offset = 3;
  }

  message ListChatRoomsResponse {
    repeated ChatRoom chat_rooms = 1;
    int32 total_count = 2;
  }

  message SendMessageRequest {
    string room_id = 1;
    string sender_id = 2;
    string content = 3;
    int32 message_type = 4;
  }

  message SendMessageResponse {
    Message message = 1;
  }

  message ListMessagesRequest {
    string room_id = 1;
    int32 limit = 2;
    int32 offset = 3;
  }

  message ListMessagesResponse {
    repeated Message messages = 1;
    int32 total_count = 2;
  }

  message MarkAsReadRequest {
    string room_id = 1;
    string user_id = 2;
    string message_id = 3;
  }

  message MarkAsReadResponse {
    bool success = 1;
  }

  message ChatRoom {
    string id = 1;
    string user1_id = 2;
    string user2_id = 3;
    bool is_active = 4;
    string last_message_at = 5;
    string created_at = 6;
    string updated_at = 7;
  }

  message Message {
    string id = 1;
    string chat_room_id = 2;
    string sender_id = 3;
    string content = 4;
    int32 message_type = 5;
    bool is_read = 6;
    string created_at = 7;
    string deleted_at = 8;
  }
  ```

